} from 'recharts';

const regionLabels: Record<string, string> = {
    all: 'All Regions', na: 'North America', eu: 'Europe',
    asean: 'ASEAN', pacific: 'Pacific', 'south-asia': 'South Asia', mena: 'MENA',
};

const SECTOR_COLORS: Record<string, string> = {
    'Defense': 'bg-red-900/30 text-red-400',
    'Healthcare': 'bg-emerald-900/30 text-emerald-400',
    'Hardware': 'bg-blue-900/30 text-blue-400',
    'Enterprise': 'bg-violet-900/30 text-violet-400',
    'Gaming': 'bg-orange-900/30 text-orange-400',
    'Consumer': 'bg-cyan-900/30 text-cyan-400',
    'Software': 'bg-indigo-900/30 text-indigo-400',
    'AI': 'bg-pink-900/30 text-pink-400',
    'Infrastructure': 'bg-amber-900/30 text-amber-400',
};

const CHART_COLORS = [
    'hsl(var(--chart-1))', 'hsl(var(--chart-2))', 'hsl(var(--chart-3))',
    'hsl(var(--chart-4))', 'hsl(var(--chart-5))', 'hsl(210, 70%, 50%)',
    'hsl(280, 60%, 55%)', 'hsl(340, 60%, 50%)',
];

const getSectorColor = (sector: string) => {
    const key = Object.keys(SECTOR_COLORS).find(k => sector.toLowerCase().includes(k.toLowerCase()));
    return SECTOR_COLORS[key || ''] || 'bg-primary/10 text-primary';
};

const formatMarketCap = (cap: number) => {
    if (cap >= 1e12) return `$${(cap / 1e12).toFixed(2)}T`;
    if (cap >= 1e9) return `$${(cap / 1e9).toFixed(1)}B`;
    return `$${(cap / 1e6).toFixed(0)}M`;
};

const PublicCompanyCard = ({ company }: { company: TrackedCompany }) => {
    const sectorColor = getSectorColor(company.sector);
    const positive = (company.priceChangePercent ?? 0) >= 0;

    return (
        <Link to={`/company/${company.slug}`}>
            <Card className="glass-premium border-black/5 hover:border-primary/50 transition-all cursor-pointer h-full group shadow-sm overflow-hidden">
                <CardHeader className="pb-4 border-b border-black/5 bg-black/[0.02]">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className={`flex h-8 w-8 items-center justify-center rounded text-[10px] font-bold shrink-0 font-mono ${sectorColor}`}>
                                {company.name.split(' ').slice(0, 2).map(w => w[0]).join('').toUpperCase()}
                            </div>
                            <div>
                                <CardTitle className="text-sm font-mono uppercase tracking-widest truncate max-w-[120px]">{company.name}</CardTitle>
                                <p className="text-[10px] font-mono text-muted-foreground uppercase tracking-tighter">{company.sector}</p>
                            </div>
                        </div>
                        {company.ticker && <Badge variant="outline" className="font-mono text-[10px] uppercase tracking-tighter bg-muted/30">{company.ticker}</Badge>}
                    </div>
                </CardHeader>
                <CardContent className="pt-4">
                    <p className="text-xs text-muted-foreground mb-4 line-clamp-2 leading-relaxed">{company.description}</p>
                    {company.ticker && (
                        <div className="grid grid-cols-2 gap-4 mb-4 p-3 rounded-lg bg-muted/20 border border-border/30">
                            <div>
                                <p className="text-[10px] font-mono text-muted-foreground uppercase tracking-wider mb-1">Stock Price</p>
                                <p className="text-sm font-mono font-bold tracking-tighter">${company.stockPrice?.toFixed(2)}</p>
                                <div className={`flex items-center gap-1 text-[10px] font-mono ${positive ? 'text-success' : 'text-destructive'}`}>
                                    {positive ? <TrendingUp className="h-3 w-3" /> : <TrendingDown className="h-3 w-3" />}
                                    {positive ? '+' : ''}{company.priceChangePercent?.toFixed(2)}%
                                </div>
                            </div>
                            <div>
                                <p className="text-[10px] font-mono text-muted-foreground uppercase tracking-wider mb-1">Market Cap</p>
                                <p className="text-sm font-mono font-bold tracking-tighter">{formatMarketCap(company.marketCap!)}</p>
                            </div>
                        </div>
                    )}
                    {company.tags && (
                        <div className="flex flex-wrap gap-1">
                            {company.tags.slice(0, 3).map(tag => (
                                <Badge key={tag} variant="outline" className="text-[9px] font-mono uppercase tracking-tighter bg-muted/30">{tag}</Badge>
                            ))}
                        </div>
                    )}
                </CardContent>
            </Card>
        </Link>
    );
};

const CompanyCard = ({ company }: { company: TrackedCompany }) => {
    const [isExpanded, setIsExpanded] = useState(false);
    const formatFunding = (amount: number) => amount >= 1000 ? `$${(amount / 1000).toFixed(1)}B` : `$${amount}M`;
    const sectorColor = getSectorColor(company.sector);
    const initials = company.name.split(' ').slice(0, 2).map(w => w[0]).join('').toUpperCase();

    return (
        <Card className="glass-premium border-black/5 hover:border-primary/50 transition-all h-full group shadow-sm overflow-hidden">
            <CardHeader className="pb-4 border-b border-black/5 bg-black/[0.02]">
                <div className="flex items-start justify-between">
                    <div className="flex items-center gap-3 flex-1">
                        <div className={`flex h-8 w-8 items-center justify-center rounded text-[10px] font-bold shrink-0 font-mono ${sectorColor}`}>
                            {initials}
                        </div>
                        <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-1">
                                <CardTitle className="text-sm font-mono uppercase tracking-widest truncate">{company.name}</CardTitle>
                                {company.type === 'unicorn' && (
                                    <Badge variant="outline" className="text-[10px] font-mono uppercase tracking-tighter bg-primary/10 text-primary border-primary/30 shrink-0">Unicorn</Badge>
                                )}
                            </div>
                            <div className="flex items-center gap-2 text-[10px] font-mono text-muted-foreground uppercase tracking-tighter">
                                <MapPin className="h-3 w-3" /><span className="truncate">{company.headquarters}</span>
                            </div>
                        </div>
                    </div>
                    <Badge variant="outline" className="text-[10px] font-mono uppercase tracking-tighter bg-muted/30 shrink-0">{company.stage}</Badge>
                </div>
            </CardHeader>
            <CardContent className="space-y-4 pt-4">
                <p className="text-xs text-muted-foreground leading-relaxed line-clamp-3">{company.description}</p>
                <div className="grid grid-cols-2 gap-3">
                    <div className="flex items-center gap-2 p-2 rounded bg-muted/20 border border-border/30">
                        <DollarSign className="h-3 w-3 text-primary" />
                        <div>
                            <p className="text-[9px] font-mono text-muted-foreground uppercase tracking-wider">{company.valuation ? 'Valuation' : 'Raised'}</p>
                            <p className="text-xs font-mono font-bold tracking-tighter">{formatFunding(company.valuation || company.totalFunding)}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 p-2 rounded bg-muted/20 border border-border/30">
                        <Users className="h-3 w-3 text-primary" />
                        <div>
                            <p className="text-[9px] font-mono text-muted-foreground uppercase tracking-wider">Employees</p>
                            <p className="text-xs font-mono font-bold tracking-tighter">{company.employees.toLocaleString()}</p>
                        </div>
                    </div>
                </div>
                {company.fundingRounds.length > 0 && (
                    <div className="flex items-center gap-2 px-1">
                        <Calendar className="h-3 w-3 text-muted-foreground" />
                        <span className="text-[10px] font-mono text-muted-foreground uppercase tracking-tighter">
                          Last: {formatFunding(company.fundingRounds[company.fundingRounds.length - 1].amount)} ({format(company.fundingRounds[company.fundingRounds.length - 1].date, 'MMM yyyy')})
                        </span>
                    </div>
                )}
                {company.tags && company.tags.length > 0 && (
                    <div className="flex flex-wrap gap-1">
                        {company.tags.slice(0, 4).map(tag => (
                            <Badge key={tag} variant="outline" className="text-[9px] font-mono uppercase tracking-tighter bg-muted/30">{tag}</Badge>
                        ))}
                    </div>
                )}
                <div className="pt-2 border-t border-border/30">
                    <button onClick={() => setIsExpanded(!isExpanded)} className="flex items-center gap-2 text-[10px] font-mono uppercase tracking-widest text-primary hover:text-primary/80 transition-colors w-full">
                        {isExpanded ? <ChevronUp className="h-3 w-3" /> : <ChevronDown className="h-3 w-3" />}
                        {isExpanded ? 'Hide Details' : 'View Intelligence'}
                    </button>
                    {isExpanded && (
                        <div className="mt-4 space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                            {company.fundingRounds.length > 0 && (
                                <div>
                                    <p className="text-[9px] font-mono text-muted-foreground mb-2 uppercase tracking-widest">Funding History</p>
                                    <div className="space-y-1.5">
                                        {company.fundingRounds.slice(-4).reverse().map((round, i) => (
                                            <div key={i} className="flex justify-between text-[10px] font-mono bg-muted/20 rounded border border-border/30 px-2 py-1.5">
                                                <div>
                                                    <span className="font-bold uppercase tracking-tight">{round.round}</span>
                                                    <span className="text-muted-foreground ml-2 uppercase">{format(round.date, 'MMM yyyy')}</span>
                                                </div>
                                                <div className="text-right">
                                                    <span className="font-bold text-primary">{formatFunding(round.amount)}</span>
                                                    {round.valuation && <span className="text-muted-foreground ml-2">@ {formatFunding(round.valuation)}</span>}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                            {company.investors.length > 0 && (
                                <div>
                                    <p className="text-[9px] font-mono text-muted-foreground mb-2 uppercase tracking-widest">Investors</p>
                                    <div className="flex flex-wrap gap-1">
                                        {company.investors.slice(0, 8).map(investor => (
                                            <Badge key={investor} variant="outline" className="text-[9px] font-mono uppercase tracking-tighter bg-muted/30">{investor}</Badge>
                                        ))}
                                    </div>
                                </div>
                            )}
                            {company.products.length > 0 && (
                                <div>
                                    <p className="text-[9px] font-mono text-muted-foreground mb-2 uppercase tracking-widest">Products</p>
                                    <div className="flex flex-wrap gap-1">
                                        {company.products.map(product => (
                                            <Badge key={product} variant="outline" className="text-[9px] font-mono uppercase tracking-tighter bg-muted/30">{product}</Badge>
                                        ))}
                                    </div>
                                </div>
                            )}
                            {company.keyMetrics && company.keyMetrics.length > 0 && (
                                <div>
                                    <p className="text-[9px] font-mono text-muted-foreground mb-2 uppercase tracking-widest">Key Metrics</p>
                                    <div className="grid grid-cols-3 gap-2">
                                        {company.keyMetrics.map((metric, i) => (
                                            <div key={i} className="bg-muted/20 border border-border/30 rounded p-2 text-center">
                                                <p className="text-xs font-bold font-mono tracking-tighter text-primary">{metric.value}</p>
                                                <p className="text-[8px] font-mono uppercase tracking-tighter text-muted-foreground">{metric.label}</p>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </CardContent>
        </Card>
    );
};

const CompanyTracker = () => {
    const { companies, stats, filters } = useCompanyTracker();
    const queryClient = useQueryClient();
    const [isRefreshing, setIsRefreshing] = useState(false);
    const { companyType, setCompanyType, selectedRegion, setSelectedRegion, searchQuery, setSearchQuery } = filters;

    const handleRefresh = async () => {
        setIsRefreshing(true);
        try {
            const { error } = await supabase.functions.invoke("daily-pipeline", {
                body: { triggered_by: "manual_tracker" },
            });
            if (error) throw error;
            toast.success("Market data pipeline triggered successfully");
            setTimeout(() => {
                queryClient.invalidateQueries({ queryKey: ["companyTracker"] });
                queryClient.invalidateQueries({ queryKey: ["marketSnapshot"] });
            }, 5000);
        } catch (error) {
            console.error("Failed to trigger pipeline:", error);
            toast.error("Failed to trigger data refresh");
        } finally {
            setIsRefreshing(false);
        }
    };

    // Compute sector distribution for charts
    const sectorDistribution = (() => {
        const sectorMap: Record<string, number> = {};
        companies.forEach(c => {
            const sector = c.sector.split('/')[0].trim();
            sectorMap[sector] = (sectorMap[sector] || 0) + 1;
        });
        return Object.entries(sectorMap)
            .sort((a, b) => b[1] - a[1])
            .slice(0, 8)
            .map(([name, value], idx) => ({ name, value, color: CHART_COLORS[idx % CHART_COLORS.length] }));
    })();

    // Stage distribution
    const stageDistribution = (() => {
        const stageMap: Record<string, number> = {};
        companies.forEach(c => {
            stageMap[c.stage] = (stageMap[c.stage] || 0) + 1;
        });
        return Object.entries(stageMap)
            .sort((a, b) => b[1] - a[1])
            .map(([name, value]) => ({ name, value }));
    })();

    return (
        <div className="min-h-screen flex flex-col">
            <Header />
            <main className="flex-1">
        <section className="py-20 border-b border-black/5 bg-secondary/30 relative overflow-hidden">
          <div className="absolute inset-0 bg-grid-subtle opacity-10 pointer-events-none" />
          <div className="container mx-auto px-4 relative z-10">
            <div className="flex flex-col md:flex-row md:items-center gap-8 mb-6">
              <div className="h-16 w-16 glass-premium flex items-center justify-center border-black/5 rounded-2xl shadow-sm">
                <Rocket className="h-8 w-8 text-primary animate-pulse" />
              </div>
              <div className="space-y-2">
                <h1 className="text-5xl font-bold font-mono tracking-tighter uppercase leading-none">Company <span className="text-primary">Tracker</span></h1>
                <p className="text-muted-foreground font-mono text-[10px] uppercase tracking-[0.5em] mt-3">
                  Global XR Entity Monitor & Performance Index
                </p>
              </div>
              <div className="ml-auto flex items-center gap-4 bg-white/50 backdrop-blur-md p-1.5 rounded-full border border-black/5 shadow-sm">
                <Button 
                  onClick={handleRefresh} 
                  disabled={isRefreshing}
                  variant="ghost"
                  size="sm"
                  className="gap-2 font-mono text-[9px] uppercase tracking-widest hover:bg-black/5 rounded-full"
                >
                  <RefreshCw className={`h-3 w-3 ${isRefreshing ? "animate-spin" : ""}`} />
                  {isRefreshing ? "Syncing..." : "Sync Monitor"}
                </Button>
              </div>
            </div>
          </div>
        </section>

        {/* Stats */}
        <section className="py-12 border-b border-black/5 bg-white/50 backdrop-blur-sm">
          <div className="container mx-auto px-4">
            <div className="grid grid-cols-2 md:grid-cols-5 gap-6">
              {[
                { icon: Building2, label: 'Total Companies', raw: stats.total },
                { icon: BarChart3, label: 'Public Companies', raw: stats.publicCount },
                { icon: TrendingUp, label: 'Unicorns', raw: stats.unicornCount },
                { icon: Rocket, label: 'Startups', raw: stats.startupCount },
                { icon: DollarSign, label: 'Total Market Cap', raw: stats.totalMarketCap || stats.totalFunding, prefix: '$', suffix: stats.totalMarketCap > 0 ? 'T' : 'B', divisor: stats.totalMarketCap > 0 ? 1e12 : 1000 },
              ].map(s => (
                <Card key={s.label} className="glass-premium border-black/5 hover:border-primary/50 transition-all group overflow-hidden shadow-sm">
                    <div className="absolute top-0 left-0 w-1 h-full bg-primary/10 group-hover:bg-primary transition-colors" />
                    <CardContent className="p-5">
                      <div className="flex items-center gap-2 mb-3">
                        <s.icon className="h-3 w-3 text-primary" />
                        <p className="text-[9px] font-mono text-muted-foreground uppercase tracking-widest">{s.label}</p>
                      </div>
                      <div className="text-2xl font-bold font-mono tracking-tighter group-hover:text-primary transition-colors">
                        <CountUp value={s.divisor ? s.raw / s.divisor : s.raw} prefix={s.prefix || ""} suffix={s.suffix || ""} decimals={s.divisor ? 1 : 0} />
                      </div>
                    </CardContent>
                </Card>
              ))}
            </div>
          </div>
        </section>

        {/* Search */}
        <section className="py-6 border-b border-border/50 bg-muted/5">
          <div className="container mx-auto px-4">
            <div className="relative w-full md:w-80">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input placeholder="SEARCH COMPANIES, SECTORS, TICKERS..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="pl-10 text-[10px] font-mono uppercase tracking-widest bg-card/50 border-border/50" />
            </div>
          </div>
        </section>

        {/* Charts */}
        <section className="py-8 border-b border-border/50">
          <div className="container mx-auto px-4">
            <div className="grid lg:grid-cols-2 gap-6">
              <Card className="bg-card/30 border-border/50">
                <CardHeader className="border-b border-border/50 bg-muted/20">
                  <CardTitle className="text-sm font-mono uppercase tracking-widest">Sector Distribution</CardTitle>
                </CardHeader>
                <CardContent className="pt-6">
                  <div className="h-[250px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={sectorDistribution} cx="50%" cy="50%" innerRadius={50} outerRadius={85} paddingAngle={2} dataKey="value">
                          {sectorDistribution.map((entry, idx) => (
                            <Cell key={idx} fill={entry.color} />
                          ))}
                        </Pie>
                        <Tooltip contentStyle={{ backgroundColor: 'hsl(var(--card))', border: '1px solid hsl(var(--border))', borderRadius: '4px', fontFamily: 'var(--font-mono)', fontSize: '10px' }} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="grid grid-cols-2 gap-2 mt-4">
                    {sectorDistribution.map(s => (
                      <div key={s.name} className="flex items-center gap-2 text-[10px] font-mono uppercase tracking-tighter">
                        <div className="h-2 w-2 rounded-full shrink-0" style={{ backgroundColor: s.color }} />
                        <span className="text-muted-foreground truncate">{s.name}</span>
                        <span className="font-bold ml-auto">{s.value}</span>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>

              <Card className="bg-card/30 border-border/50">
                <CardHeader className="border-b border-border/50 bg-muted/20">
                  <CardTitle className="text-sm font-mono uppercase tracking-widest">Stage Distribution</CardTitle>
                </CardHeader>
                <CardContent className="pt-6">
                  <div className="h-[280px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={stageDistribution} layout="vertical" margin={{ left: 70 }}>
                        <XAxis type="number" axisLine={false} tickLine={false} tick={{ fill: 'hsl(var(--muted-foreground))', fontSize: 10, fontFamily: 'var(--font-mono)' }} />
                        <YAxis type="category" dataKey="name" axisLine={false} tickLine={false} tick={{ fill: 'hsl(var(--muted-foreground))', fontSize: 10, fontFamily: 'var(--font-mono)' }} width={65} />
                        <Tooltip contentStyle={{ backgroundColor: 'hsl(var(--card))', border: '1px solid hsl(var(--border))', borderRadius: '4px', fontFamily: 'var(--font-mono)', fontSize: '10px' }} />
                        <Bar dataKey="value" fill="hsl(var(--primary))" radius={[0, 2, 2, 0]} />
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
                </CardContent>
              </Card>
            </div>
          </div>
        </section>

        {/* Company Grid with Tabs */}
        <section className="py-10">
          <div className="container mx-auto px-4">
            <Tabs value={companyType} onValueChange={(v) => setCompanyType(v as "all" | "public" | "unicorn" | "startup")}>
              <TabsList className="mb-8 bg-muted/20 border border-border/50 p-1">
                <TabsTrigger value="all" className="data-[state=active]:bg-primary data-[state=active]:text-primary-foreground font-mono text-[10px] uppercase tracking-widest px-6">All Companies</TabsTrigger>
                <TabsTrigger value="public" className="data-[state=active]:bg-primary data-[state=active]:text-primary-foreground font-mono text-[10px] uppercase tracking-widest px-6">Public Companies</TabsTrigger>
                <TabsTrigger value="unicorn" className="data-[state=active]:bg-primary data-[state=active]:text-primary-foreground font-mono text-[10px] uppercase tracking-widest px-6">Unicorns</TabsTrigger>
                <TabsTrigger value="startup" className="data-[state=active]:bg-primary data-[state=active]:text-primary-foreground font-mono text-[10px] uppercase tracking-widest px-6">Emerging Startups</TabsTrigger>
              </TabsList>

              <div className="mb-8 p-4 rounded-lg bg-muted/10 border border-border/30">
                <p className="text-[10px] font-mono text-muted-foreground mb-3 uppercase tracking-widest">Filter by Region:</p>
                <div className="flex flex-wrap gap-2">
                  {Object.entries(regionLabels).map(([code, label]) => (
                    <Badge
                      key={code}
                      variant={selectedRegion === code ? 'default' : 'outline'}
                      className="cursor-pointer text-[10px] font-mono uppercase tracking-tighter px-3 py-1"
                      onClick={() => setSelectedRegion(code as any)}
                    >
                      {label}
                    </Badge>
                  ))}
                </div>
              </div>

              <TabsContent value={companyType} className="mt-0">
                {companies.length > 0 ? (
                  <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {companies.map(company => (
                      company.type === 'public'
                        ? <PublicCompanyCard key={company.id} company={company} />
                        : <CompanyCard key={company.id} company={company} />
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-20 border border-dashed border-border/50 rounded-xl">
                    <p className="text-xs font-mono text-muted-foreground uppercase tracking-widest">No companies found matching your criteria</p>
                  </div>
                )}
              </TabsContent>
            </Tabs>
          </div>
        </section>
            </main>
            <Footer />
        </div>
    );
};

export default CompanyTracker;

import { Header } from "@/components/layout/Header";
import { Footer } from "@/components/layout/Footer";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useMarketSnapshot } from "@/hooks/useMarketSnapshot";
import { useNewsItems } from "@/hooks/useNewsItems";
import { companies as staticCompanies } from "@/data/companies";
import { startups } from "@/data/startups";
import { unicorns } from "@/data/unicorns";
import {
  TrendingUp, TrendingDown, DollarSign, Activity,
  ArrowUpRight, ArrowDownRight, Building2, Layers, BarChart3,
  RefreshCw, Cpu, Globe, Zap, Clock, Search, ExternalLink
} from "lucide-react";
import {
  AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell, LineChart, Line,
  XAxis, YAxis, Tooltip, ResponsiveContainer, Legend,
  RadialBarChart, RadialBar, ScatterChart, Scatter, ZAxis,
  RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar,
} from "recharts";
import { format } from "date-fns";
import { useMemo, useState } from "react";
import { PipelineStatus } from "@/components/dashboard/PipelineStatus";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";
import { useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import { CountUp } from "@/components/shared/CountUp";
import { MarketTicker } from "@/components/home/MarketTicker";

const SECTOR_MAP: Record<string, string> = {
  AAPL: "Hardware", META: "Social/Metaverse", MSFT: "Enterprise", NVDA: "Semiconductor",
  GOOG: "Software/AI", GOOGL: "Software/AI", SONY: "Gaming/Hardware", QCOM: "Semiconductor",
  SNAP: "Social/AR", RBLX: "Gaming", U: "Gaming Engine", "005930.KS": "Hardware",
  MTTR: "Enterprise", VUZI: "Hardware", IMMR: "Input Tech", MVIS: "LiDAR/Sensing",
  KOPN: "Displays", LAZR: "LiDAR/Sensing", AEVA: "LiDAR/Sensing",
};

const SEGMENT_COLORS = [
  "hsl(var(--chart-1))", "hsl(var(--chart-2))", "hsl(var(--chart-3))",
  "hsl(var(--chart-4))", "hsl(var(--chart-5))", "hsl(210, 70%, 50%)",
  "hsl(280, 60%, 55%)", "hsl(340, 60%, 50%)", "hsl(160, 55%, 45%)",
];

// Industry research estimates (analyst consensus)
const tamSamSomData = [
  { name: "TAM", value: 280, fill: "hsl(var(--chart-1))", label: "$280B" },
  { name: "SAM", value: 85, fill: "hsl(var(--chart-2))", label: "$85B" },
  { name: "SOM", value: 24, fill: "hsl(var(--chart-3))", label: "$24B" },
];

const growthProjections = [
  { year: "2024", hardware: 18, software: 22, services: 28, content: 35 },
  { year: "2025", hardware: 21, software: 26, services: 32, content: 42 },
  { year: "2026", hardware: 25, software: 31, services: 38, content: 48 },
  { year: "2027", hardware: 28, software: 36, services: 44, content: 55 },
  { year: "2028", hardware: 32, software: 42, services: 52, content: 62 },
];

const formatMarketCap = (value?: number | null) => {
  if (!value) return "—";
  if (value >= 1e12) return `$${(value / 1e12).toFixed(1)}T`;
  if (value >= 1e9) return `$${(value / 1e9).toFixed(1)}B`;
  if (value >= 1e6) return `$${(value / 1e6).toFixed(0)}M`;
  return `$${value.toLocaleString()}`;
};

const formatVolume = (value: number) => {
  if (value >= 1e9) return `${(value / 1e9).toFixed(1)}B`;
  if (value >= 1e6) return `${(value / 1e6).toFixed(1)}M`;
  if (value >= 1e3) return `${(value / 1e3).toFixed(1)}K`;
  return value.toLocaleString();
};

const formatAxisDate = (value: string) => {
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return format(parsed, "MMM d");
};

const Dashboard = () => {
  const { data: snapshot, isLoading: isSnapshotLoading } = useMarketSnapshot();
  const { data: newsItems } = useNewsItems(5);
  const queryClient = useQueryClient();
  const [isRefreshing, setIsRefreshing] = useState(false);

  const handleRefresh = async () => {
    setIsRefreshing(true);
    try {
      const { error } = await supabase.functions.invoke("daily-pipeline", {
        body: { triggered_by: "manual_dashboard" },
      });
      if (error) throw error;
      toast.success("Market data pipeline triggered successfully");
      // Invalidate queries to show new data when it's ready
      setTimeout(() => {
        queryClient.invalidateQueries({ queryKey: ["marketSnapshot"] });
        queryClient.invalidateQueries({ queryKey: ["pipelineStatus"] });
      }, 5000);
    } catch (error) {
      console.error("Failed to trigger pipeline:", error);
      toast.error("Failed to trigger data refresh");
    } finally {
      setIsRefreshing(false);
    }
  };

  const indexSeries = snapshot?.indexSeries ?? [];
  const latestIndex = indexSeries.length > 0 ? indexSeries[indexSeries.length - 1] : undefined;
  const prevIndex = indexSeries.length > 1 ? indexSeries[indexSeries.length - 2] : undefined;
  const indexChangePercent = latestIndex && prevIndex && prevIndex.value !== 0
    ? ((latestIndex.value - prevIndex.value) / prevIndex.value) * 100 : 0;

  const liveCompanies = snapshot?.topCompanies || [];
  const hasLiveStats = liveCompanies.length > 0;
  const snapshotCompanies = [...liveCompanies].sort((a, b) => (b.marketCap ?? 0) - (a.marketCap ?? 0));
  const totalVolume = snapshotCompanies.reduce((sum, c) => sum + (c.volume || 0), 0);

  // Compute from real static data
  const computedData = useMemo(() => {
    const totalMarketCap = hasLiveStats 
      ? liveCompanies.reduce((s, c) => s + (c.marketCap || 0), 0)
      : staticCompanies.reduce((s, c) => s + c.marketCap, 0);

    const totalRAndD = staticCompanies.reduce((s, c) => s + c.metrics.rAndDSpend, 0);
    const totalRevenue = hasLiveStats
      ? liveCompanies.reduce((s, c) => s + (c.price * (c.volume || 0) / 1000), 0)
      : staticCompanies.reduce((s, c) => s + c.revenue, 0);

    const uniqueSectors = new Set(staticCompanies.map(c => c.sector)).size;
    const totalTracked = staticCompanies.length + startups.length + unicorns.length;

    // Competitive radar from actual company metrics
    const radarCompanies = hasLiveStats ? liveCompanies.slice(0, 5) : staticCompanies.slice(0, 5);
    const maxMCap = Math.max(...radarCompanies.map(c => c.marketCap || 0));
    const maxRev = Math.max(...radarCompanies.map(c => hasLiveStats ? (c.price * (c.volume || 0) / 1000) : (c as any).revenue || 0));
    const maxChange = Math.max(...radarCompanies.map(c => Math.abs(c.changePercent || 0)));

    const normalize = (val: number, max: number) => max > 0 ? Math.round((val / max) * 100) : 0;

    const radarSubjects = ['Market Cap', 'Volume', 'Daily Change', 'Momentum', 'Scale'];
    const radarData = radarSubjects.map((subject, i) => {
      const row: Record<string, any> = { subject };
      radarCompanies.forEach(c => {
        const name = c.name.split(' ')[0];
        const val = hasLiveStats ? c : (c as any);
        switch (i) {
          case 0: row[name] = normalize(val.marketCap || 0, maxMCap); break;
          case 1: row[name] = normalize(hasLiveStats ? val.volume : val.employees || 0, hasLiveStats ? Math.max(...liveCompanies.map(lc => lc.volume || 1)) : 100000); break;
          case 2: row[name] = normalize(Math.abs(val.changePercent || 0), maxChange); break;
          case 3: row[name] = normalize((val.changePercent || 0) + 50, 100); break; 
          case 4: row[name] = normalize(val.marketCap || 0, maxMCap); break;
        }
      });
      return row;
    });

    // Funding funnel from actual data
    const stageCounts: Record<string, number> = {};
    startups.forEach(s => { stageCounts[s.stage] = (stageCounts[s.stage] || 0) + 1; });
    const unicornCount = unicorns.length;
    const funnelData = [
      { name: 'Seed', value: stageCounts['Seed'] || 0, fill: 'hsl(var(--chart-1))' },
      { name: 'Series A', value: stageCounts['Series A'] || 0, fill: 'hsl(var(--chart-2))' },
      { name: 'Series B', value: stageCounts['Series B'] || 0, fill: 'hsl(var(--chart-3))' },
      { name: 'Series C', value: stageCounts['Series C'] || 0, fill: 'hsl(var(--chart-4))' },
      { name: 'Series D+', value: (stageCounts['Series D+'] || 0) + (stageCounts['Growth'] || 0), fill: 'hsl(var(--chart-5))' },
      { name: 'Unicorn', value: unicornCount, fill: 'hsl(210, 70%, 50%)' },
    ];

    // Stock performance ranking
    const stockRanking = (hasLiveStats ? liveCompanies : staticCompanies.filter(c => c.ticker))
      .sort((a: any, b: any) => (b.changePercent || 0) - (a.changePercent || 0))
      .map((c: any) => ({
        ticker: c.symbol || c.ticker!, 
        name: c.name, 
        sector: c.sector || SECTOR_MAP[c.symbol] || "Other", 
        price: c.price || c.stockPrice,
        change: c.changePercent || c.priceChangePercent, 
        marketCap: c.marketCap, 
        revenue: (c as any).revenue || (c.price * (c.volume || 0) / 1000),
        peRatio: (c as any).metrics?.peRatio || 25.4, 
        margin: (c as any).metrics?.grossMargin || 32,
      }));

    const top5Names = radarCompanies.map(c => c.name.split(' ')[0]);

    return {
      totalMarketCap, totalRAndD, totalRevenue, uniqueSectors, totalTracked,
      radarData, radarSubjects, top5Names,
      funnelData, stockRanking,
    };
  }, [snapshot, hasLiveStats, liveCompanies]);

  // Segment data from snapshot
  const segmentData = (() => {
    if (snapshotCompanies.length === 0) return [];
    const sectorTotals: Record<string, number> = {};
    snapshotCompanies.forEach(c => {
      const sector = SECTOR_MAP[c.symbol] ?? "Other";
      sectorTotals[sector] = (sectorTotals[sector] ?? 0) + (c.marketCap ?? 0);
    });
    const totalCap = Object.values(sectorTotals).reduce((s, v) => s + v, 0);
    if (totalCap === 0) return [];
    return Object.entries(sectorTotals).sort((a, b) => b[1] - a[1])
      .map(([name, value], idx) => ({ name, value: Math.round((value / totalCap) * 1000) / 10, color: SEGMENT_COLORS[idx % SEGMENT_COLORS.length] }));
  })();

  // Sector performance
  const sectorPerformance = (() => {
    if (snapshotCompanies.length === 0) return [];
    const sectorChanges: Record<string, number[]> = {};
    snapshotCompanies.forEach(c => {
      const sector = SECTOR_MAP[c.symbol] ?? "Other";
      if (!sectorChanges[sector]) sectorChanges[sector] = [];
      sectorChanges[sector].push(c.changePercent);
    });
    return Object.entries(sectorChanges)
      .map(([sector, changes]) => ({ sector, avgChange: Math.round((changes.reduce((s, v) => s + v, 0) / changes.length) * 100) / 100, count: changes.length }))
      .sort((a, b) => b.avgChange - a.avgChange);
  })();

  const scatterData = snapshotCompanies.slice(0, 15).map(c => ({
    x: c.marketCap ? c.marketCap / 1e9 : 0, y: c.changePercent, z: c.volume / 1e6, name: c.symbol,
  }));

  const hasSnapshot = Boolean(indexSeries.length && snapshotCompanies.length);

  const kpiCards = [
    { title: "Total XR Market Cap", value: computedData.totalMarketCap, raw: computedData.totalMarketCap, change: "", positive: true, icon: DollarSign, description: `${staticCompanies.length} tracked companies`, prefix: "$", divisor: 1e12, suffix: "T" },
    { title: "Total R&D Investment", value: computedData.totalRAndD, raw: computedData.totalRAndD, change: "", positive: true, icon: Activity, description: "annual R&D spend", prefix: "$", divisor: 1e9, suffix: "B" },
    { title: "Sectors Covered", value: computedData.uniqueSectors, raw: computedData.uniqueSectors, change: "", positive: true, icon: Layers, description: "unique sectors" },
    { title: "Companies Tracked", value: computedData.totalTracked, raw: computedData.totalTracked, change: "", positive: true, icon: Building2, description: "public + private" },
  ];

  const lastUpdatedLabel = snapshot?.asOfDate ? format(new Date(snapshot.asOfDate), "MMM d, yyyy") : "—";

  return (
    <div className="min-h-screen flex flex-col">
      <Header />
      <main className="flex-1 container py-10">
        <div className="mb-12 flex flex-col md:flex-row md:items-end justify-between gap-6 border-b border-border/50 pb-10">
          <div>
            <div className="flex items-center gap-3 mb-3">
              <h1 className="text-4xl md:text-5xl font-bold font-mono tracking-tighter uppercase">Intelligence Terminal</h1>
              <Badge variant="outline" className="flex items-center gap-2 bg-success/10 text-success border-success/30 px-3 py-1 font-mono text-[10px] uppercase tracking-widest">
                <span className="flex h-2 w-2 rounded-full bg-success animate-pulse shadow-[0_0_8px_rgba(var(--success),0.5)]" />
                Live Feed Active
              </Badge>
            </div>
            <p className="text-muted-foreground max-w-2xl font-mono text-sm tracking-tight">Spatial computing market metrics, company analytics, and investment data. Real-time processing enabled.</p>
            <div className="flex flex-wrap items-center gap-4 mt-4">
              <p className="text-[10px] font-mono text-muted-foreground uppercase tracking-[0.2em] bg-muted/30 px-2 py-1 rounded border border-border/30">Last Snapshot: {lastUpdatedLabel}</p>
              <p className="text-[10px] font-mono text-primary-text font-bold uppercase tracking-[0.2em] animate-pulse">System Status: Optimal</p>
              {snapshot?.provider && (
                <Badge variant="outline" className={`text-[9px] font-mono uppercase tracking-widest ${snapshot.provider.includes("EMULATED") ? "text-warning border-warning/30 bg-warning/5" : "text-success border-success/30 bg-success/5"}`}>
                  Source: {snapshot.provider}
                </Badge>
              )}
            </div>
          </div>
          <Button 
            onClick={handleRefresh} 
            disabled={isRefreshing}
            variant="outline"
            className="gap-3 font-mono text-[10px] uppercase tracking-[0.3em] border-primary/30 hover:bg-primary hover:text-primary-foreground transition-all duration-300 px-6 h-12"
          >
            <RefreshCw className={`h-4 w-4 ${isRefreshing ? "animate-spin" : ""}`} />
            {isRefreshing ? "Syncing..." : "Sync Market Data"}
          </Button>
        </div>

        {/* KPI Cards */}
        <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          {kpiCards.map(kpi => (
            <Card key={kpi.title} className="bg-card/30 border-border/50 hover:border-primary/50 transition-all group overflow-hidden relative">
              <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
                <kpi.icon className="h-12 w-12 text-primary" />
              </div>
              <CardContent className="pt-8 text-primary-text">
                <div className="text-3xl font-bold mb-2 font-mono tracking-tighter group-hover:text-primary transition-colors text-foreground">
                  <CountUp 
                    value={kpi.divisor ? kpi.raw / kpi.divisor : kpi.raw} 
                    prefix={kpi.prefix || ""} 
                    suffix={kpi.suffix || ""} 
                    decimals={kpi.divisor ? 1 : 0} 
                  />
                </div>
                <div className="text-[10px] font-mono uppercase tracking-[0.2em] text-muted-foreground mb-4 border-b border-border/30 pb-2">{kpi.title}</div>
                <div className="text-[9px] font-mono text-muted-foreground/50 uppercase tracking-widest flex items-center gap-2 group-hover:text-foreground/70 transition-colors">
                  <Activity className="h-3 w-3 text-primary/50" />
                  {kpi.description}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>

        {/* Stock Performance Ranking */}
        <Card className="bg-card/30 border-border/50 mb-12 overflow-hidden shadow-2xl shadow-primary/5">
          <CardHeader className="border-b border-border/50 bg-muted/20 py-4">
            <CardTitle className="flex items-center gap-3 text-xs font-mono uppercase tracking-[0.3em] text-muted-foreground">
              <BarChart3 className="h-4 w-4 text-primary" />
              XR Market Capitalization Index
            </CardTitle>
          </CardHeader>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full text-sm font-mono">
                <thead>
                  <tr className="border-b border-border/50 bg-muted/10">
                    <th className="text-left py-4 px-6 text-[9px] uppercase tracking-[0.2em] text-muted-foreground">#</th>
                    <th className="text-left py-4 px-6 text-[9px] uppercase tracking-[0.2em] text-muted-foreground">Ticker</th>
                    <th className="text-left py-4 px-6 text-[9px] uppercase tracking-[0.2em] text-muted-foreground">Entity</th>
                    <th className="text-left py-4 px-6 text-[9px] uppercase tracking-[0.2em] text-muted-foreground hidden md:table-cell">Sector</th>
                    <th className="text-right py-4 px-6 text-[9px] uppercase tracking-[0.2em] text-muted-foreground">Price</th>
                    <th className="text-right py-4 px-6 text-[9px] uppercase tracking-[0.2em] text-muted-foreground">Change</th>
                    <th className="text-right py-4 px-6 text-[9px] uppercase tracking-[0.2em] text-muted-foreground hidden sm:table-cell">Market Cap</th>
                    <th className="text-right py-4 px-6 text-[9px] uppercase tracking-[0.2em] text-muted-foreground hidden lg:table-cell">P/E</th>
                    <th className="text-right py-4 px-6 text-[9px] uppercase tracking-[0.2em] text-muted-foreground hidden lg:table-cell">Margin</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border/30">
                  {computedData.stockRanking.map((stock, idx) => {
                    const positive = stock.change >= 0;
                    return (
                      <tr key={stock.ticker} className="hover:bg-primary/5 transition-all group cursor-pointer">
                        <td className="py-4 px-6 text-muted-foreground text-[10px]">{idx + 1}</td>
                        <td className="py-4 px-6 font-bold text-primary-text text-xs tracking-widest group-hover:translate-x-1 transition-transform">{stock.ticker}</td>
                        <td className="py-4 px-6 font-medium text-xs uppercase tracking-tight text-foreground">{stock.name}</td>
                        <td className="py-4 px-6 text-muted-foreground hidden md:table-cell italic text-[10px] uppercase tracking-tighter">{stock.sector}</td>
                        <td className="py-4 px-6 text-right text-xs font-bold text-foreground">${stock.price.toFixed(2)}</td>
                        <td className={`py-4 px-6 text-right text-xs font-bold ${positive ? 'text-success' : 'text-destructive'}`}>
                          <span className="flex items-center justify-end gap-1">
                            {positive ? <TrendingUp className="h-3 w-3" /> : <TrendingDown className="h-3 w-3" />}
                            {positive ? "+" : ""}{stock.change.toFixed(2)}%
                          </span>
                        </td>
                        <td className="py-4 px-6 text-right text-xs hidden sm:table-cell">{formatMarketCap(stock.marketCap)}</td>
                        <td className="py-4 px-6 text-right text-xs hidden lg:table-cell">{stock.peRatio?.toFixed(1) ?? '—'}</td>
                        <td className="py-4 px-6 text-right text-xs hidden lg:table-cell">{stock.margin.toFixed(1)}%</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>

        {/* Market Index + Segments */}
        <div className="grid lg:grid-cols-3 gap-8 mb-12">
          <Card className="lg:col-span-2 bg-card/30 border-border/50 shadow-xl shadow-primary/5">
            <CardHeader className="border-b border-border/50 bg-muted/20 py-4">
              <CardTitle className="text-xs font-mono uppercase tracking-[0.3em] text-muted-foreground">XR Market Performance Trend</CardTitle>
            </CardHeader>
            <CardContent className="pt-8">
              <Tabs defaultValue="area" className="w-full">
                <div className="flex justify-end mb-6">
                  <TabsList className="bg-muted/30 border border-border/50 p-1">
                    <TabsTrigger value="area" className="text-[9px] font-mono uppercase tracking-widest px-4 py-1 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground">Area</TabsTrigger>
                    <TabsTrigger value="line" className="text-[9px] font-mono uppercase tracking-widest px-4 py-1 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground">Line</TabsTrigger>
                  </TabsList>
                </div>
                <TabsContent value="area">
                  <div className="h-[350px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={indexSeries}>
                        <defs><linearGradient id="colorIndex" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="hsl(var(--chart-2))" stopOpacity={0.3} /><stop offset="95%" stopColor="hsl(var(--chart-2))" stopOpacity={0} /></linearGradient></defs>
                        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 9, fontFamily: "var(--font-mono)" }} tickFormatter={formatAxisDate} />
                        <YAxis axisLine={false} tickLine={false} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 9, fontFamily: "var(--font-mono)" }} tickFormatter={v => v.toFixed(0)} />
                        <Tooltip contentStyle={{ backgroundColor: "rgba(var(--card), 0.9)", backdropFilter: "blur(8px)", border: "1px solid hsl(var(--border))", borderRadius: "4px", fontFamily: "var(--font-mono)", fontSize: "10px" }} formatter={(value: number) => [value.toFixed(2), "INDEX"]} labelFormatter={formatAxisDate} />
                        <Area type="monotone" dataKey="value" name="Index" stroke="hsl(var(--chart-2))" fillOpacity={1} fill="url(#colorIndex)" strokeWidth={3} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </TabsContent>
                <TabsContent value="line">
                  <div className="h-[350px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <LineChart data={indexSeries}>
                        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 9, fontFamily: "var(--font-mono)" }} tickFormatter={formatAxisDate} />
                        <YAxis axisLine={false} tickLine={false} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 9, fontFamily: "var(--font-mono)" }} tickFormatter={v => v.toFixed(0)} />
                        <Tooltip contentStyle={{ backgroundColor: "rgba(var(--card), 0.9)", backdropFilter: "blur(8px)", border: "1px solid hsl(var(--border))", borderRadius: "4px", fontFamily: "var(--font-mono)", fontSize: "10px" }} formatter={(value: number) => [value.toFixed(2), "INDEX"]} labelFormatter={formatAxisDate} />
                        <Line type="monotone" dataKey="value" name="Index" stroke="hsl(var(--chart-2))" strokeWidth={3} dot={false} />
                      </LineChart>
                    </ResponsiveContainer>
                  </div>
                </TabsContent>
              </Tabs>
            </CardContent>
          </Card>

          <Card className="bg-card/30 border-border/50 shadow-xl shadow-primary/5">
            <CardHeader className="border-b border-border/50 bg-muted/20 py-4">
              <CardTitle className="text-xs font-mono uppercase tracking-[0.3em] text-muted-foreground">Market Segments</CardTitle>
            </CardHeader>
            <CardContent className="pt-8">
              {segmentData.length > 0 ? (
                <>
                  <div className="h-[280px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={segmentData} cx="50%" cy="50%" innerRadius={70} outerRadius={100} paddingAngle={4} dataKey="value">
                          {segmentData.map((entry, index) => (<Cell key={index} fill={entry.color} stroke="transparent" />))}
                        </Pie>
                        <Tooltip contentStyle={{ backgroundColor: "rgba(var(--card), 0.9)", backdropFilter: "blur(8px)", border: "1px solid hsl(var(--border))", borderRadius: "4px", fontFamily: "var(--font-mono)", fontSize: "10px" }} formatter={(value: number) => [`${value}%`, ""]} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="space-y-3 mt-8">
                    {segmentData.map(segment => (
                      <div key={segment.name} className="flex items-center justify-between text-[9px] font-mono uppercase tracking-[0.2em] group">
                        <div className="flex items-center gap-3">
                          <div className="h-2 w-2 rounded-full shadow-[0_0_5px_currentColor]" style={{ backgroundColor: segment.color, color: segment.color }} />
                          <span className="text-muted-foreground group-hover:text-primary transition-colors">{segment.name}</span>
                        </div>
                        <span className="font-bold tracking-tighter">{segment.value}%</span>
                      </div>
                    ))}
                  </div>
                </>
              ) : (
                <div className="flex flex-col items-center justify-center h-[350px] text-center">
                  <RefreshCw className="h-8 w-8 text-muted-foreground/30 animate-spin mb-4" />
                  <p className="text-[10px] font-mono text-muted-foreground uppercase tracking-widest">Initializing Data Stream...</p>
                </div>
              )}
            </CardContent>
          </Card>
        </div>

        {/* TAM/SAM/SOM + Sector Heatmap */}
        <div className="grid lg:grid-cols-2 gap-8 mb-12">
          <Card className="bg-card/30 border-border/50 shadow-xl shadow-primary/5">
            <CardHeader className="border-b border-border/50 bg-muted/20 py-4">
              <CardTitle className="text-xs font-mono uppercase tracking-[0.3em] text-muted-foreground">Spatial Computing Market Sizing (2030)</CardTitle>
              <p className="text-[9px] font-mono text-muted-foreground uppercase tracking-widest mt-1">Industry research estimates / Aggregate consensus</p>
            </CardHeader>
            <CardContent className="pt-6">
              <div className="h-[250px]">
                <ResponsiveContainer width="100%" height="100%">
                  <RadialBarChart cx="50%" cy="50%" innerRadius="30%" outerRadius="90%" barSize={20} data={tamSamSomData}>
                    <RadialBar dataKey="value" cornerRadius={6} />
                    <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "4px", fontFamily: "var(--font-mono)", fontSize: "10px" }} formatter={(value: number, _: string, props: { payload: { name: string } }) => [`$${value}B`, props.payload.name.toUpperCase()]} />
                  </RadialBarChart>
                </ResponsiveContainer>
              </div>
              <div className="grid grid-cols-3 gap-3 mt-4">
                {tamSamSomData.map(item => (
                  <div key={item.name} className="text-center p-3 rounded-lg bg-muted/20 border border-border/50">
                    <p className="text-lg font-bold font-mono tracking-tighter" style={{ color: item.fill }}>{item.label}</p>
                    <p className="text-[10px] font-mono uppercase tracking-widest text-muted-foreground">{item.name}</p>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          <Card className="bg-card/30 border-border/50">
            <CardHeader className="border-b border-border/50 bg-muted/20">
              <CardTitle className="text-sm font-mono uppercase tracking-widest">Sector Performance (Daily)</CardTitle>
            </CardHeader>
            <CardContent className="pt-6">
              {sectorPerformance.length > 0 ? (
                <div className="space-y-3">
                  {sectorPerformance.map(s => (
                    <div key={s.sector} className="flex items-center gap-3">
                      <span className="text-[10px] font-mono uppercase tracking-widest text-muted-foreground w-32 truncate">{s.sector}</span>
                      <div className="flex-1 h-6 rounded-sm overflow-hidden bg-muted/20 relative border border-border/30">
                        <div className={`absolute inset-y-0 left-0 ${s.avgChange >= 0 ? "bg-success/20" : "bg-destructive/20"}`} style={{ width: `${Math.min(Math.abs(s.avgChange) * 20, 100)}%` }} />
                        <span className={`absolute inset-0 flex items-center justify-center text-[10px] font-mono font-bold ${s.avgChange >= 0 ? "text-success" : "text-destructive"}`}>
                          {s.avgChange >= 0 ? "+" : ""}{s.avgChange}%
                        </span>
                      </div>
                      <Badge variant="outline" className="text-[10px] font-mono min-w-[32px] justify-center h-5">{s.count}</Badge>
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-xs font-mono text-muted-foreground italic">No sector data available.</p>
              )}
            </CardContent>
          </Card>
        </div>

        {/* Growth + Scatter */}
        <div className="grid lg:grid-cols-2 gap-6 mb-8">
          <Card className="bg-card/30 border-border/50">
            <CardHeader className="border-b border-border/50 bg-muted/20">
              <CardTitle className="text-sm font-mono uppercase tracking-widest">XR Market Growth by Segment ($B)</CardTitle>
              <p className="text-[10px] font-mono text-muted-foreground uppercase tracking-wider">Industry analyst projections</p>
            </CardHeader>
            <CardContent className="pt-6">
              <div className="h-[280px]">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={growthProjections}>
                    <XAxis dataKey="year" axisLine={false} tickLine={false} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 10, fontFamily: "var(--font-mono)" }} />
                    <YAxis axisLine={false} tickLine={false} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 10, fontFamily: "var(--font-mono)" }} tickFormatter={v => `$${v}B`} />
                    <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "4px", fontFamily: "var(--font-mono)", fontSize: "10px" }} formatter={(value: number) => [`$${value}B`]} />
                    <Legend wrapperStyle={{ fontSize: "10px", fontFamily: "var(--font-mono)", textTransform: "uppercase" }} />
                    <Bar dataKey="hardware" name="Hardware" fill="hsl(var(--chart-1))" radius={[2, 2, 0, 0]} />
                    <Bar dataKey="software" name="Software" fill="hsl(var(--chart-2))" radius={[2, 2, 0, 0]} />
                    <Bar dataKey="services" name="Services" fill="hsl(var(--chart-3))" radius={[2, 2, 0, 0]} />
                    <Bar dataKey="content" name="Content" fill="hsl(var(--chart-4))" radius={[2, 2, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>

          <Card className="bg-card/30 border-border/50">
            <CardHeader className="border-b border-border/50 bg-muted/20">
              <CardTitle className="text-sm font-mono uppercase tracking-widest">Market Cap vs Daily Change</CardTitle>
            </CardHeader>
            <CardContent className="pt-6">
              {scatterData.length > 0 ? (
                <div className="h-[280px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <ScatterChart margin={{ left: 10, right: 10 }}>
                      <XAxis type="number" dataKey="x" name="Market Cap" axisLine={false} tickLine={false} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 10, fontFamily: "var(--font-mono)" }} tickFormatter={v => `$${v > 1000 ? `${(v/1000).toFixed(1)}T` : `${v.toFixed(0)}B`}`} />
                      <YAxis type="number" dataKey="y" name="Change %" axisLine={false} tickLine={false} tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 10, fontFamily: "var(--font-mono)" }} tickFormatter={v => `${v}%`} />
                      <ZAxis type="number" dataKey="z" range={[40, 400]} name="Volume" />
                      <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "4px", fontFamily: "var(--font-mono)", fontSize: "10px" }} />
                      <Scatter data={scatterData} fill="hsl(var(--chart-2))" />
                    </ScatterChart>
                  </ResponsiveContainer>
                </div>
              ) : (
                <p className="text-xs font-mono text-muted-foreground italic">No snapshot data available.</p>
              )}
            </CardContent>
          </Card>
        </div>

        {/* Competitive Radar + Funding Funnel */}
        <div className="grid lg:grid-cols-2 gap-6 mb-8">
          <Card className="bg-card/30 border-border/50">
            <CardHeader className="border-b border-border/50 bg-muted/20">
              <CardTitle className="text-sm font-mono uppercase tracking-widest">Top 5 XR Companies – Competitive Radar</CardTitle>
              <p className="text-[10px] font-mono text-muted-foreground uppercase tracking-wider">Computed from actual company metrics</p>
            </CardHeader>
            <CardContent className="pt-6">
              <div className="h-[320px]">
                <ResponsiveContainer width="100%" height="100%">
                  <RadarChart data={computedData.radarData} cx="50%" cy="50%" outerRadius="70%">
                    <PolarGrid stroke="hsl(var(--border))" />
                    <PolarAngleAxis dataKey="subject" tick={{ fill: "hsl(var(--muted-foreground))", fontSize: 10, fontFamily: "var(--font-mono)" }} />
                    <PolarRadiusAxis tick={false} axisLine={false} />
                    {computedData.top5Names.map((name, i) => (
                      <Radar key={name} name={name} dataKey={name} stroke={SEGMENT_COLORS[i]} fill={SEGMENT_COLORS[i]} fillOpacity={i === 0 ? 0.15 : 0.1} strokeWidth={2} />
                    ))}
                    <Legend wrapperStyle={{ fontSize: "10px", fontFamily: "var(--font-mono)", textTransform: "uppercase" }} />
                    <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "4px", fontFamily: "var(--font-mono)", fontSize: "10px" }} />
                  </RadarChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>

          <Card className="bg-card/30 border-border/50">
            <CardHeader className="border-b border-border/50 bg-muted/20">
              <CardTitle className="text-sm font-mono uppercase tracking-widest">XR Startup Funding Funnel</CardTitle>
              <p className="text-[10px] font-mono text-muted-foreground uppercase tracking-wider">From {startups.length} tracked startups & {unicorns.length} unicorns</p>
            </CardHeader>
            <CardContent className="pt-6">
              <div className="space-y-3">
                {computedData.funnelData.filter(s => s.value > 0).map(stage => {
                  const maxVal = Math.max(...computedData.funnelData.map(d => d.value));
                  const widthPercent = (stage.value / maxVal) * 100;
                  return (
                    <div key={stage.name} className="flex items-center gap-3">
                      <span className="text-[10px] font-mono uppercase tracking-widest text-muted-foreground w-20 text-right shrink-0">{stage.name}</span>
                      <div className="flex-1 relative h-9 bg-muted/10 rounded-sm border border-border/30 overflow-hidden">
                        <div className="absolute inset-y-0 left-0 flex items-center justify-end pr-3 transition-all duration-1000 ease-out" style={{ width: `${widthPercent}%`, backgroundColor: stage.fill, opacity: 0.8 }}>
                          <span className="text-[10px] font-mono font-bold text-white">{stage.value}</span>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
              <div className="mt-6 grid grid-cols-3 gap-3">
                <div className="text-center p-3 rounded-lg bg-muted/20 border border-border/50">
                  <p className="text-lg font-bold font-mono tracking-tighter text-primary">{startups.length}</p>
                  <p className="text-[10px] font-mono uppercase tracking-widest text-muted-foreground">Startups</p>
                </div>
                <div className="text-center p-3 rounded-lg bg-muted/20 border border-border/50">
                  <p className="text-lg font-bold font-mono tracking-tighter text-primary">{unicorns.length}</p>
                  <p className="text-[10px] font-mono uppercase tracking-widest text-muted-foreground">Unicorns</p>
                </div>
                <div className="text-center p-3 rounded-lg bg-muted/20 border border-border/50">
                  <p className="text-lg font-bold font-mono tracking-tighter text-primary">{startups.length > 0 ? ((unicorns.length / (startups.length + unicorns.length)) * 100).toFixed(1) : 0}%</p>
                  <p className="text-[10px] font-mono uppercase tracking-widest text-muted-foreground">Unicorn Rate</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Pipeline Status */}
        <div className="mb-8">
          <PipelineStatus />
        </div>

        {/* Bottom: News */}
        <Card className="bg-card/30 border-border/50">
          <CardHeader className="border-b border-border/50 bg-muted/20">
            <CardTitle className="text-sm font-mono uppercase tracking-widest">Latest Market Intelligence</CardTitle>
          </CardHeader>
          <CardContent className="pt-6">
            <div className="space-y-6">
              {newsItems && newsItems.length > 0 ? (
                newsItems.map(item => (
                  <div key={item.id} className="flex gap-4 group">
                    <div className="flex h-2 w-2 mt-2 shrink-0 rounded-full bg-primary animate-pulse" />
                    <div className="flex-1">
                      <p className="text-sm font-medium group-hover:text-primary transition-colors cursor-pointer leading-snug">{item.title}</p>
                      <div className="flex items-center gap-3 mt-2">
                        {item.source && <Badge variant="outline" className="text-[10px] font-mono uppercase tracking-tighter bg-muted/30">{item.source}</Badge>}
                        <span className="text-[10px] font-mono text-muted-foreground uppercase">
                          {item.publishedAt ? format(new Date(item.publishedAt), "MMM d, yyyy") : "—"}
                        </span>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <p className="text-xs font-mono text-muted-foreground italic">No news ingested yet.</p>
              )}
            </div>
          </CardContent>
        </Card>
      </main>
      <Footer />
    </div>
  );
};

export default Dashboard;

import { useState } from 'react';
import { Header } from '@/components/layout/Header';
import { Footer } from '@/components/layout/Footer';
import { Card, CardContent } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Mail, CheckCircle, TrendingUp, BarChart3, Zap } from 'lucide-react';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

const Newsletter = () => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [subscribed, setSubscribed] = useState(false);

  const handleSubscribe = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !email.includes('@')) return;
    setLoading(true);
    try {
      const { error } = await supabase.from('newsletter_subscribers' as any).insert({ email });
      if (error) {
        if (error.code === '23505') {
          toast.info('You\'re already subscribed!');
        } else {
          throw error;
        }
      } else {
        setSubscribed(true);
        toast.success('Successfully subscribed!');
      }
    } catch {
      toast.error('Failed to subscribe. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header />
      <main className="flex-1">
        <section className="py-16 border-b border-border/50 bg-muted/10">
          <div className="container mx-auto px-4 max-w-3xl text-center">
            <div className="h-16 w-16 rounded-2xl bg-primary/10 flex items-center justify-center border border-primary/20 mx-auto mb-6">
              <Mail className="h-8 w-8 text-primary" />
            </div>
            <h1 className="text-5xl font-bold font-mono tracking-tighter uppercase mb-4">Intelligence Briefing</h1>
            <p className="text-muted-foreground font-mono text-sm uppercase tracking-[0.2em] max-w-xl mx-auto leading-relaxed">
              Weekly strategic insights on spatial computing investments, market shifts, and emerging ecosystems
            </p>
          </div>
        </section>

        <section className="py-20">
          <div className="container mx-auto px-4 max-w-2xl">
            {subscribed ? (
              <Card className="bg-card/30 border-primary/30 text-center overflow-hidden shadow-2xl shadow-primary/5">
                <CardContent className="pt-12 pb-12">
                  <div className="h-20 w-20 rounded-full bg-success/10 flex items-center justify-center border border-success/20 mx-auto mb-6">
                    <CheckCircle className="h-10 w-10 text-success" />
                  </div>
                  <h2 className="text-2xl font-bold font-mono tracking-tight uppercase mb-2">Registration Confirmed</h2>
                  <p className="text-muted-foreground font-mono text-xs uppercase tracking-widest">Awaiting next intelligence transmission</p>
                </CardContent>
              </Card>
            ) : (
              <Card className="bg-card/30 border-border/50 shadow-xl">
                <CardContent className="p-8">
                  <form onSubmit={handleSubscribe} className="flex flex-col sm:flex-row gap-4">
                    <Input
                      type="email"
                      placeholder="OPERATOR_EMAIL@DOMAIN.COM"
                      value={email}
                      onChange={e => setEmail(e.target.value)}
                      required
                      maxLength={255}
                      className="flex-1 font-mono text-xs uppercase tracking-widest bg-muted/20 border-border/50 h-12"
                    />
                    <Button type="submit" disabled={loading} className="h-12 px-8 font-mono text-xs uppercase tracking-[0.2em] bg-primary hover:bg-primary/90 transition-all">
                      {loading ? 'Processing...' : 'Initialize Access'}
                    </Button>
                  </form>
                  <p className="text-[9px] font-mono text-muted-foreground uppercase tracking-tighter mt-4 text-center opacity-50">
                    By subscribing, you agree to receive strategic intelligence updates. Opt-out anytime.
                  </p>
                </CardContent>
              </Card>
            )}

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mt-16">
              {[
                { icon: TrendingUp, label: 'Market Moves', desc: 'Weekly XR index recap' },
                { icon: BarChart3, label: 'Deal Flow', desc: 'Latest funding rounds' },
                { icon: Zap, label: 'Insights', desc: 'AI-curated analysis' },
              ].map(f => (
                <Card key={f.label} className="bg-card/30 border-border/50 text-center hover:border-primary/30 transition-all group">
                  <CardContent className="pt-8 pb-8">
                    <f.icon className="h-6 w-6 text-primary mx-auto mb-4 group-hover:scale-110 transition-transform" />
                    <h3 className="text-[10px] font-mono font-bold uppercase tracking-[0.2em] mb-2">{f.label}</h3>
                    <p className="text-[9px] font-mono text-muted-foreground uppercase tracking-tighter leading-tight">{f.desc}</p>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        </section>
      </main>
      <Footer />
    </div>
  );
};

export default Newsletter;

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Header } from '@/components/layout/Header';
import { Footer } from '@/components/layout/Footer';
import { format } from 'date-fns';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { 
    Share2, 
    Linkedin, 
    Instagram, 
    Layout, 
    CheckCircle2, 
    Clock, 
    AlertCircle,
    Settings,
    Database,
    ExternalLink,
    RefreshCw
} from 'lucide-react';
import { toast } from 'sonner';

const SocialControlRoom = () => {
    const [isConnecting, setIsConnecting] = useState<string | null>(null);
    const [integrations, setIntegrations] = useState<any[]>([]);
    const [recentPosts, setRecentPosts] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setIsLoading(true);
        try {
            const { data: intData } = await supabase.from('integrations' as any).select('*');
            const { data: postData } = await supabase.from('social_posts' as any).select('*, content_items(title)').order('created_at', { ascending: false }).limit(10);

            setIntegrations(intData || []);
            setRecentPosts(postData || []);
        } catch (error) {
            console.error("Fetch data error:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const platforms = [
        { id: 'canva', name: 'Canva Enterprise', icon: Layout, description: 'Autofill API for carousel generation' },
        { id: 'linkedin', name: 'LinkedIn Prof.', icon: Linkedin, description: 'Native publishing' },
        { id: 'meta', name: 'Meta (IG/FB)', icon: Instagram, description: 'Instagram Graph API' },
    ];

    const getStatus = (id: string) => {
        const int = integrations.find(i => i.platform === id);
        return int?.access_token ? 'connected' : 'disconnected';
    };

    const connectPlatform = (id: string) => {
        setIsConnecting(id);
        toast.info(`Initiating OAuth flow for ${id}...`);
        // Mocking OAuth redirect
        setTimeout(() => {
            setIsConnecting(null);
            toast.error("OAuth configuration incomplete. Please set up environment variables.");
        }, 1500);
    };

    return (
        <div className="min-h-screen flex flex-col">
            <Header />
            <main className="flex-1">
                <section className="py-20 border-b border-black/5 bg-secondary/30 relative overflow-hidden">
                    <div className="absolute inset-0 bg-grid-subtle opacity-10 pointer-events-none" />
                    <div className="container mx-auto px-4 relative z-10">
                        <div className="flex flex-col md:flex-row md:items-center gap-8 mb-6">
                            <div className="h-16 w-16 glass-premium flex items-center justify-center border-black/5 rounded-2xl shadow-sm">
                                <Share2 className="h-8 w-8 text-primary animate-pulse" />
                            </div>
                            <div className="space-y-2">
                                <h1 className="text-5xl font-bold font-mono tracking-tighter uppercase leading-none">Social <span className="text-primary">Control</span></h1>
                                <p className="text-muted-foreground font-mono text-[10px] uppercase tracking-[0.5em] mt-3">
                                    Automated Content Distribution Pipeline
                                </p>
                            </div>
                        </div>
                    </div>
                </section>

                <div className="container mx-auto px-4 py-12">
                    <div className="grid lg:grid-cols-3 gap-8">
                        {/* Status Grid */}
                        <div className="lg:col-span-2 space-y-8">
                            <div className="grid md:grid-cols-3 gap-4">
                                {platforms.map((platform) => {
                                    const status = getStatus(platform.id);
                                    return (
                                        <Card key={platform.id} className="glass-premium border-black/5 shadow-sm overflow-hidden group">
                                            <CardHeader className="pb-4">
                                                <div className="flex items-center justify-between mb-2">
                                                    <platform.icon className={`h-6 w-6 ${status === 'connected' ? 'text-primary' : 'text-muted-foreground'}`} />
                                                    <Badge variant={status === 'connected' ? 'default' : 'outline'} className="text-[9px] font-mono uppercase tracking-tighter">
                                                        {status}
                                                    </Badge>
                                                </div>
                                                <CardTitle className="text-sm font-mono uppercase tracking-widest">{platform.name}</CardTitle>
                                                <CardDescription className="text-[10px] uppercase font-mono tracking-tight leading-relaxed">
                                                    {platform.description}
                                                </CardDescription>
                                            </CardHeader>
                                            <CardContent>
                                                <Button 
                                                    variant={status === 'connected' ? 'outline' : 'default'}
                                                    className="w-full h-8 text-[9px] font-mono uppercase tracking-widest border-black/5"
                                                    onClick={() => connectPlatform(platform.id)}
                                                    disabled={isConnecting === platform.id}
                                                >
                                                    {status === 'connected' ? 'Reconnect' : 'Connect'}
                                                </Button>
                                            </CardContent>
                                        </Card>
                                    );
                                })}
                            </div>

                            {/* Recent Activity */}
                            <Card className="glass-premium border-black/5 shadow-sm overflow-hidden">
                                <CardHeader className="border-b border-black/5 bg-black/[0.02]">
                                    <div className="flex items-center justify-between">
                                        <CardTitle className="text-xs font-mono uppercase tracking-[0.3em]">Pipeline Activity Monitor</CardTitle>
                                        <div className="flex items-center gap-2">
                                            {isLoading && <RefreshCw className="h-3 w-3 text-muted-foreground animate-spin" />}
                                            <Button variant="ghost" size="icon" className="h-6 w-6" onClick={fetchData} disabled={isLoading}>
                                                <RefreshCw className={`h-3 w-3 text-muted-foreground ${isLoading ? 'animate-spin' : ''}`} />
                                            </Button>
                                        </div>
                                    </div>
                                </CardHeader>
                                <CardContent className="p-0">
                                    <div className="divide-y divide-black/5">
                                        {recentPosts.length > 0 ? recentPosts.map((post) => (
                                            <div key={post.id} className="p-4 flex items-center justify-between hover:bg-black/[0.01] transition-colors">
                                                <div className="flex items-center gap-4">
                                                    <div className={`p-2 rounded-lg ${
                                                        post.status === 'published' ? 'bg-success/10 text-success' : 
                                                        post.status === 'failed' ? 'bg-destructive/10 text-destructive' : 
                                                        'bg-primary/10 text-primary'
                                                    }`}>
                                                        {post.status === 'published' ? <CheckCircle2 className="h-4 w-4" /> : 
                                                         post.status === 'failed' ? <AlertCircle className="h-4 w-4" /> : 
                                                         <Clock className="h-4 w-4" />}
                                                    </div>
                                                    <div>
                                                        <h4 className="text-xs font-bold font-mono uppercase tracking-tight">{post.content_items?.title || 'Unknown Post'}</h4>
                                                        <div className="flex items-center gap-2 mt-1">
                                                            <span className="text-[9px] font-mono text-muted-foreground uppercase">{post.status}</span>
                                                            <span className="h-1 w-1 rounded-full bg-muted/40" />
                                                            <span className="text-[9px] font-mono text-muted-foreground uppercase">{format(new Date(post.created_at), 'MMM d, yyyy')}</span>
                                                        </div>
                                                    </div>
